#include <bits/stdc++.h>
#define int long long
using namespace std;

signed main() {
    int n;
    cin >> n;

    if(n == 1) {
        int x;
        cin >> x;
        cout << x;
        return 0;
    }

    bool all_positive = true;
    bool all_negative = true;
    int sum = 0;
    vector<int> a(n);

    for(int i = 0; i < n; i++) {
        cin >> a[i];
        if(a[i] > 0) all_negative = false;
        if(a[i] < 0) all_positive = false;
        sum += abs(a[i]);
    }

    if(all_positive || all_negative) {
        int min_abs = LLONG_MAX;
        for(int x : a) {
            min_abs = min(min_abs, abs(x));
        }
        cout << sum - 2 * min_abs;
    }
    else {
        cout << sum;
    }

    return 0;
}

